def tc_blocks() -> str:
    blocks = []
    for raw in TCS:
        if raw[1] in {"Positive", "Negative"}:
            tc_id, tc_type, package_id, priority, title, trace, pre, data, steps, expected, post = raw
        else:
            tc_id, package_id, tc_type, priority, title, trace, pre, data, steps, expected, post = raw
        step_text = "\n".join(f"{idx}. {step}" for idx, step in enumerate(steps, start=1))
        blocks.append(
            f"""## {tc_id}

**Название:** {title}
**Тип:** {tc_type}
**Приоритет:** {priority}
**package_id:** {package_id}
**Трассировка:** {trace}

### Предусловия

{pre}

### Тестовые данные

{data}

### Шаги

{step_text}

### Итоговый ожидаемый результат

{expected}

### Постусловия

{post}
"""
        )
    return "\n\n".join(blocks)


def normalization_rows() -> list[list[str]]:
    return PROPERTIES


def props_for_source(source_row_id: str) -> list[list[str]]:
    return [row for row in PROPERTIES if row[0] == source_row_id]


def tc_for_atom(atom_id: str) -> str:
    for atom in ATOMS:
        if atom[0] == atom_id:
            return atom[6]
    return "`not_covered:GAP-001`"


def atom_for_property(source_property_id: str) -> str:
    for prop in PROPERTIES:
        if prop[1] == source_property_id:
            return prop[11]
    return "`not_covered:GAP-001`"


def ids_from(value: str, prefix: str) -> list[str]:
    return re.findall(rf"{prefix}-[A-Z0-9]+", value)


